diffPreview:
chat.router.ts (conceptual diff)
- const toolResult = await executeTool(...)
+ let toolResult: ToolResult;
+ try {
+   toolResult = await executeTool(...)
+ } catch (err:any) {
+   toolResult = {
+     name: toolName,
+     args: toolArgs,
+     error: true,
+     result: `${toolName} runtime failure: ${err?.message || err}. Continuing on current model/provider.`
+   };
+ }
+ // always push/send tool_result + role:tool message

+ if (toolName === 'switch_model' && toolResult.error) {
+   clearTurnModelOverride(sessionId);
+   sendSSE('model_switch_failed', { reason: toolResult.result });
+ }

cis-system.ts / prompt-context.ts
- Auto-reverts to Codex after the turn ends
+ Auto-reverts to the session's configured primary model/provider after the turn ends

